#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int isLucky(int num) {
    while (num > 0) {
        int digit = num % 10;
        if (digit != 4 && digit != 7) return 0;
        num /= 10;
    }
    return 1;
}

int luckySum(int a, int b) {
    int maxLen = strlen(getMax(a, b));
    int sum = 0;
    for (int i = 0; i < maxLen; i++) {
        int digitA = getDigit(a, i);
        int digitB = getDigit(b, i);
        sum = sum * 10 + (digitA > digitB ? digitA : digitB);
    }
    return sum;
}

int getDigit(int num, int pos) {
    int digit = 0;
    for (int i = 0; i < pos; i++) num /= 10;
    digit = num % 10;
    return digit;
}

int getMax(int a, int b) {
    return a > b ? a : b;
}

int countLuckySubsequences(int* arr, int n) {
    int count = 0;
    for (int i = 1; i < (1 << n); i++) {
        int sum = 0;
        for (int j = 0; j < n; j++) {
            if ((i & (1 << j)) != 0) {
                if (sum == 0) sum = arr[j];
                else sum = luckySum(sum, arr[j]);
            }
        }
        if (isLucky(sum)) count++;
    }
    return count;
