import java.util.Scanner;
public class Main {
    public static boolean isLucky(int num) {
        while (num > 0) {
            int digit = num % 10;
            if (digit != 4 && digit != 7) return false;
            num /= 10;
        }
        return true;
    }

    public static int luckySum(int a, int b) {
        int maxLen = String.valueOf(Math.max(a, b)).length();
        int sum = 0;
        for (int i = 0; i < maxLen; i++) {
            int digitA = (a / (int)Math.pow(10, i)) % 10;
            int digitB = (b / (int)Math.pow(10, i)) % 10;
            sum = sum * 10 + (digitA > digitB ? digitA : digitB);
        }
        return sum;
    }

    public static int countLuckySubsequences(int[] arr) {
        int count = 0;
        int n = arr.length;
        for (int i = 1; i < (1 << n); i++) {
            int sum = 0;
            for (int j = 0; j < n; j++) {
                if ((i & (1 << j)) != 0) {
                    if (sum == 0) sum = arr[j];
                    else sum = luckySum(sum, arr[j]);
                }
            }
            if (isLucky(sum)) count++;
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) arr[i] = scanner.nextInt();
            System.out.println(countLuckySubsequences(arr));
        }
    }
}

