        digit = num % 10
        if digit != 4 and digit != 7:
            return False
        num //= 10
    return True


def lucky_sum(a, b):
    max_len = max(len(str(a)), len(str(b)))
    sum = 0
    for i in range(max_len):
        digit_a = (a // (10 ** i)) % 10
        digit_b = (b // (10 ** i)) % 10
        sum = sum * 10 + (digit_a if digit_a > digit_b else digit_b)
    return sum


